mapper.select:
select count(*)
from fact_cards
where review_status = #{reviewStatus}

with query as ( select plainto_tsquery(cast(#{tsConfig} as regconfig), #{question}) as tsq ) select fc.source_id, fc.card_id as item_key, fc.card_id as concept_id, fc.title, trim(concat_ws(E'\n\n', coalesce(fc.claim, ''), coalesce(fc.items_json::text, ''), coalesce(fc.evidence_text, ''))) as content, jsonb_build_object( 'factCardId', fc.id, 'cardId', fc.card_id, 'sourceFileId', fc.source_file_id, 'cardType', fc.card_type, 'answerShape', fc.answer_shape, 'confidence', fc.confidence, 'sourceChunkIds', coalesce(to_jsonb(fc.source_chunk_ids), '[]'::jsonb), 'articleIds', coalesce(to_jsonb(fc.article_ids), '[]'::jsonb) )::text as metadata_json, fc.review_status, array_remove(array[sf.file_path], null)::text[] as source_paths, null::integer as chunk_index, false as verbatim, ts_rank_cd(fc.search_tsv, query.tsq)
+ case when lower(fc.title) like #{likeToken} then 3.0 else 0 end + case when lower(fc.claim) like #{likeToken} then 4.0 else 0 end + case when lower(fc.items_json::text) like #{likeToken} then 4.0 else 0 end + case when lower(fc.evidence_text) like #{likeToken} then 3.0 else 0 end + case when lower(fc.card_type) like #{likeToken} then 1.0 else 0 end + case when lower(fc.answer_shape) like #{likeToken} then 1.0 else 0 end
as score from fact_cards fc left join source_files sf on sf.id = fc.source_file_id cross join query where fc.search_tsv @@ query.tsq
or lower(fc.title) like #{likeToken} or lower(fc.claim) like #{likeToken} or lower(fc.items_json::text) like #{likeToken} or lower(fc.evidence_text) like #{likeToken} or lower(fc.card_type) like #{likeToken} or lower(fc.answer_shape) like #{likeToken}
order by score desc, fc.updated_at desc, fc.card_id asc limit #{limit}
